proc isolatedTarget(bot: Bot): tuple[found: bool, crewmate: CrewmateMatch] =
  ## Returns a crewmate to kill when safe. Safe means:
  ## (a) exactly 1 non-imposter visible, OR
  ## (b) nearest non-imposter is in kill range and next-nearest is far (>60px).
  let nonImpCount = bot.visibleNonImposterCount()
  if nonImpCount == 0:
    return
  if nonImpCount == 1:
    for crewmate in bot.visibleCrewmates:
      if crewmate.colorIndex == bot.selfColorIndex:
        continue
      if bot.knownImposterColor(crewmate.colorIndex):
        continue
      return (true, crewmate)
  # Multiple visible: only attack if nearest is in kill range and others far.
  var
    bestDist = high(int)
    secondDist = high(int)
    bestCrewmate: CrewmateMatch
  for crewmate in bot.visibleCrewmates:
    if crewmate.colorIndex == bot.selfColorIndex:
      continue
    if bot.knownImposterColor(crewmate.colorIndex):
      continue
    let
      world = bot.visibleCrewmateWorld(crewmate)
      dist = heuristic(bot.playerWorldX(), bot.playerWorldY(), world.x, world.y)
    if dist < bestDist:
      secondDist = bestDist
      bestDist = dist
      bestCrewmate = crewmate
    elif dist < secondDist:
      secondDist = dist
  if bestDist <= bot.sim.config.killRange and secondDist > 60:
    return (true, bestCrewmate)

