proc decideImposterMask(bot: var Bot): uint8 {.measure.} =
  ## Chooses imposter movement and kill behavior.
  ## Strategy: kill ASAP when isolated with one crewmate, avoid partner,
  ## prowl away from partner to maximize map coverage for parallel kills.
  bot.radarDots.setLen(0)
  if bot.radarTasks.len != bot.sim.tasks.len:
    bot.radarTasks = newSeq[bool](bot.sim.tasks.len)
  if bot.checkoutTasks.len != bot.sim.tasks.len:
    bot.checkoutTasks = newSeq[bool](bot.sim.tasks.len)
  for i in 0 ..< bot.radarTasks.len:
    bot.radarTasks[i] = false
  for i in 0 ..< bot.checkoutTasks.len:
    bot.checkoutTasks[i] = false
  bot.taskHoldTicks = 0
  bot.taskHoldIndex = -1

  # Flee from bodies we made to avoid being caught near them.
  let body = bot.nearestBody()
  if body.found:
    bot.imposterGoalIndex = bot.farthestFakeTargetIndexFrom(body.x, body.y)
    let fleeGoal = bot.fakeTargetGoalFor(bot.imposterGoalIndex)
    if fleeGoal.found:
      bot.goalIndex = fleeGoal.index
      return bot.navigateToPoint(
        fleeGoal.x,
        fleeGoal.y,
        "flee body to " & fleeGoal.name
      )

  if bot.imposterHuntActive():
    # Core strategy: only kill when alone with exactly one crewmate.
    let isolated = bot.isolatedTarget()
    if isolated.found:
      return bot.attackVisibleCrewmate(
        isolated.crewmate,
        "isolated kill " & playerColorName(isolated.crewmate.colorIndex)
      )

    # If partner is visible, move to a prowl point far from them.
    let partner = bot.imposterPartnerWorld()
    if partner.found:
      let farIndex = bot.farthestFakeTargetIndexFrom(partner.x, partner.y)
      let farGoal = bot.fakeTargetGoalFor(farIndex)
      if farGoal.found:
        bot.imposterGoalIndex = farIndex
        bot.goalIndex = farGoal.index
        return bot.navigateToPoint(
          farGoal.x,
          farGoal.y,
          "spread from partner to " & farGoal.name
        )

    # Nobody around or multiple witnesses: prowl to find isolated targets.
    return bot.navigateProwlPoint()

  # Early game: fake tasks but pick targets far from partner.
  let partner = bot.imposterPartnerWorld()
